const { dirname } = require("path");
const { readFile, writeFile, mkdir } = require("fs/promises");
const { JSDOM } = require("jsdom");
const { minify } = require("html-minifier-terser");

const [IN, IN_CSS, IN_JS, OUT] = process.argv.slice(2);
readFile(IN, "utf8")
	.then(file => new JSDOM(file))
	.then(dom => {
		const document = dom.window.document;
		return Promise.all([
			readFile(IN_CSS, "utf8")
				.then(css => {
					const style = document.createElement("style");
					style.innerHTML = css;
					document.head.appendChild(style);
					document.head.querySelectorAll("link[rel='stylesheet']")
						.forEach(el => void document.head.removeChild(el));
				}),
			readFile(IN_JS, "utf8")
				.then(js => {
					const script = document.createElement("script");
					script.type = "application/javascript";
					script.innerHTML = js;
					document.body.appendChild(script);
					document.head.removeChild(document.head.querySelector("script"));
				}),
			mkdir(dirname(OUT), { recursive: true })
		])
			.then(_results => minify(dom.serialize(), {
				html5: true,
				useShortDoctype: true,
				collapseBooleanAttributes: true,
				collapseWhitespace: true,
				conservativeCollapse: true,
				removeComments: true,
				includeAutoGeneratedTags: false,
			}));
	})
	.then(html => writeFile(OUT, html, "utf8"))
	.catch(error => {
		if (error) {
			console.error(error);
		}
		return process.exit(1);
	});
